import React, { useState, useRef, useEffect } from 'react';
import {
  Container,
  Box,
  TextField,
  IconButton,
  Paper,
  Typography,
  CircularProgress,
  AppBar,
  Toolbar,
  Drawer,
  Button,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Divider,
} from '@mui/material';
import { ThemeProvider } from '@mui/material/styles';
import SendIcon from '@mui/icons-material/Send';
import AddIcon from '@mui/icons-material/Add';
import ChatIcon from '@mui/icons-material/Chat';
import DescriptionIcon from '@mui/icons-material/Description';
import { styled } from '@mui/material/styles';
import Message from './components/Message';
import Documents from './components/Documents';
import { chatService } from './services/api';
import theme from './theme';
import './App.css';
import 'bootstrap/dist/css/bootstrap.min.css';

// Styled components
const ChatContainer = styled(Paper)(({ theme }) => ({
  height: 'calc(100vh - 140px)',
  display: 'flex',
  flexDirection: 'column',
  backgroundColor: theme.palette.background.default,
  borderRadius: theme.spacing(2),
  overflow: 'hidden',
}));

const MessagesArea = styled(Box)(({ theme }) => ({
  flex: 1,
  overflowY: 'auto',
  padding: theme.spacing(2),
  backgroundColor: theme.palette.background.paper,
}));

const InputArea = styled(Box)(({ theme }) => ({
  padding: theme.spacing(2),
  backgroundColor: theme.palette.background.paper,
  borderTop: `1px solid ${theme.palette.divider}`,
}));

// Sidebar width
const DRAWER_WIDTH = 280;

function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState('checking');
  const [conversations, setConversations] = useState([
    { id: 1, title: 'New Conversation', active: true }
  ]);
  const messagesEndRef = useRef(null);
  const [currentPage, setCurrentPage] = useState('chat'); // 'chat' or 'documents'

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Check backend connection on component mount
  useEffect(() => {
    const checkConnection = async () => {
      try {
        await chatService.checkHealth();
        setConnectionStatus('connected');
      } catch (error) {
        console.error('Backend connection error:', error);
        setConnectionStatus('disconnected');
      }
    };

    checkConnection();
  }, []);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMessage = { role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await chatService.sendMessage(input);
      const assistantMessage = { role: 'assistant', content: response.response };
      
      // If there are similar tickets, add them as context
      if (response.similar_tickets && response.similar_tickets.length > 0) {
        // Extract ticket information properly
        const ticketInfoArray = response.similar_tickets.map(ticket => {
          // Extract ticket info based on actual structure from the API
          const id = ticket.number || ticket.ticket_id || ticket.sys_id || ticket.u_number || 'Unknown';
          const title = ticket.short_description || ticket.title || 'No Description';
          const status = ticket.state || ticket.status || 'Unknown Status';
          return `Ticket #${id}: ${title} (${status})`;
        });
        
        const contextMessage = {
          role: 'system',
          content: '**Similar tickets found:**\n' + ticketInfoArray.join('\n'),
          tickets: response.similar_tickets // Store the full ticket objects
        };
        setMessages(prev => [...prev, contextMessage]);
      }
      
      setMessages(prev => [...prev, assistantMessage]);
    } catch (error) {
      console.error('Error:', error);
      const errorMessage = {
        role: 'assistant',
        content: `Error: ${error.message || 'An error occurred while processing your request.'}`,
      };
      setMessages(prev => [...prev, errorMessage]);
    }

    setIsLoading(false);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <ThemeProvider theme={theme}>
      <Box sx={{ display: 'flex', height: '100vh' }}>
        {/* ChatGPT-like Sidebar */}
        <Drawer
          variant="permanent"
          sx={{
            width: DRAWER_WIDTH,
            flexShrink: 0,
            '& .MuiDrawer-paper': {
              width: DRAWER_WIDTH,
              boxSizing: 'border-box',
              bgcolor: 'secondary.main',
              color: 'white',
            },
          }}
        >
          <Box sx={{ p: 2, mt: 8 }}> {/* Add margin-top for the AppBar */}
            <Button 
              fullWidth
              startIcon={<AddIcon />}
              variant="outlined"
              sx={{
                color: 'white',
                borderColor: 'rgba(255,255,255,0.2)',
                mb: 2,
                textTransform: 'none',
                justifyContent: 'flex-start'
              }}
              onClick={() => setCurrentPage('chat')}
            >
              New chat
            </Button>
            
            <Button 
              fullWidth
              startIcon={<DescriptionIcon />}
              variant="outlined"
              sx={{
                color: 'white',
                borderColor: 'rgba(255,255,255,0.2)',
                mb: 2,
                textTransform: 'none',
                justifyContent: 'flex-start',
                bgcolor: currentPage === 'documents' ? 'rgba(255,255,255,0.1)' : 'transparent'
              }}
              onClick={() => setCurrentPage('documents')}
            >
              Documents
            </Button>
            
            <Divider sx={{ bgcolor: 'rgba(255,255,255,0.1)', my: 2 }} />
            
            <List sx={{ mt: 1 }}>
              {conversations.map((conv) => (
                <ListItem 
                  key={conv.id} 
                  button 
                  selected={conv.active && currentPage === 'chat'}
                  sx={{
                    mb: 1,
                    borderRadius: 1,
                    '&.Mui-selected': {
                      bgcolor: 'rgba(255,255,255,0.1)',
                    },
                    '&:hover': {
                      bgcolor: 'rgba(255,255,255,0.05)',
                    }
                  }}
                  onClick={() => setCurrentPage('chat')}
                >
                  <ChatIcon sx={{ mr: 1, fontSize: '1.2rem' }} />
                  <ListItemText primary={conv.title} primaryTypographyProps={{ noWrap: true }} />
                </ListItem>
              ))}
            </List>
          </Box>
        </Drawer>

        {/* Main Content */}
        <Box sx={{ flexGrow: 1, display: 'flex', flexDirection: 'column' }}>
          <AppBar position="fixed" color="primary" sx={{ zIndex: (theme) => theme.zIndex.drawer + 1 }}>
            <Toolbar>
              <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
                Aspire CMDB Support Assistant
              </Typography>
              {currentPage === 'chat' && (
                <Box 
                  sx={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    gap: 1,
                    backgroundColor: connectionStatus === 'connected' ? 'success.main' : 
                                  connectionStatus === 'checking' ? 'warning.main' : 'error.main',
                    padding: '4px 12px',
                    borderRadius: 1,
                  }}
                >
                  <Typography variant="body2">
                    {connectionStatus === 'connected' ? 'Connected' :
                    connectionStatus === 'checking' ? 'Checking Connection...' : 'Disconnected'}
                  </Typography>
                </Box>
              )}
            </Toolbar>
          </AppBar>

          {/* Content based on current page */}
          <Box sx={{ mt: 8, p: 2, flexGrow: 1 }}>
            {currentPage === 'chat' ? (
              <ChatContainer elevation={3}>
                <MessagesArea>
                  {messages.map((message, index) => (
                    <Message 
                      key={index} 
                      message={message} 
                      tickets={message.tickets} 
                    />
                  ))}
                  {isLoading && (
                    <Box display="flex" justifyContent="center" my={2}>
                      <CircularProgress />
                    </Box>
                  )}
                  <div ref={messagesEndRef}></div>
                </MessagesArea>

                <InputArea>
                  <Box component="form" onSubmit={(e) => e.preventDefault()} sx={{ display: 'flex', gap: 2 }}>
                    <TextField
                      fullWidth
                      value={input}
                      onChange={(e) => setInput(e.target.value)}
                      onKeyPress={handleKeyPress}
                      placeholder={
                        connectionStatus === 'checking' 
                          ? "Checking connection..." 
                          : connectionStatus === 'disconnected' 
                          ? "Waiting for backend connection..." 
                          : "Type your message..."
                      }
                      variant="outlined"
                      size="small"
                      disabled={connectionStatus !== 'connected' || isLoading}
                    />
                    <IconButton
                      color="primary"
                      onClick={handleSend}
                      disabled={!input.trim() || isLoading || connectionStatus !== 'connected'}
                    >
                      {isLoading ? <CircularProgress size={24} /> : <SendIcon />}
                    </IconButton>
                  </Box>
                  {connectionStatus === 'disconnected' && (
                    <Typography color="error" variant="caption" sx={{ mt: 1, display: 'block' }}>
                      Unable to connect to backend server. Please ensure the server is running.
                    </Typography>
                  )}
                </InputArea>
              </ChatContainer>
            ) : (
              <Documents />
            )}
          </Box>
        </Box>
      </Box>
    </ThemeProvider>
  );
}

export default App;
